    const n = grid[0].length;
    const dist = Array(m).fill().map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const pq = new PriorityQueue((a, b) => a.cost - b.cost);
    pq.enqueue({ cost: 0, i: 0, j: 0, moves: 0 });

    const directions = [[0, 1], [1, 0]]; // right, down

    while (!pq.isEmpty()) {
        const { cost, i, j, moves } = pq.dequeue();
        if (i === m - 1 && j === n - 1) return cost;
        if (moves > k) continue;

        // Regular move: right or down
        for (const [di, dj] of directions) {
            const ni = i + di;
            const nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj]) {
                    dist[ni][nj] = newCost;
                    pq.enqueue({ cost: newCost, i: ni, j: nj, moves });
                }
            }
        }

        // Teleport: find all cells with value <= current cell's value
        for (let x = 0; x < m; x++) {
            for (let y = 0; y < n; y++) {
                if (grid[x][y] <= grid[i][j] && x !== i && y !== j) {
                    if (dist[x][y] > cost) {
                        dist[x][y] = cost;
                        pq.enqueue({ cost: cost, i: x, j: y, moves });
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

